import React from 'react';
import UploadDropzone from '../components/ui/UploadDropzone';
import FileCard from '../components/ui/FileCard';
import './FilesPage.css';

const FilesPage = ({ 
  selectedGroup, 
  files, 
  uploadFileToGroup, 
  tags, 
  setTags, 
  downloadFile, 
  deleteFile, 
  formatSize, 
  formatDate,
  loading
}) => {
  return (
    <div className="files-page fade-in">
      <div className="page-header">
        <h1 className="page-title">{selectedGroup?.name || 'Group Files'}</h1>
        <p className="muted">
          {selectedGroup?.name === "__NETWORK_SHARE__" 
            ? "Files available to everyone on the network"
            : "Files shared within this group"}
        </p>
      </div>

      <UploadDropzone 
        onUpload={uploadFileToGroup} 
        tags={tags} 
        setTags={setTags} 
        loading={loading}
      />

      <div className="files-section">
        <div className="section-header">
          <h3>Shared Files</h3>
          <span className="file-count-badge">{files.length}</span>
        </div>

        {files.length === 0 ? (
          <div className="empty-state">
            <span className="empty-icon">📁</span>
            <h3>No Files Yet</h3>
            <p>Be the first to upload a file to this group!</p>
          </div>
        ) : (
          <div className="files-grid">
            {files.map((file) => (
              <FileCard 
                key={file._id}
                file={file}
                onDownload={downloadFile}
                onDelete={selectedGroup?.name !== "__NETWORK_SHARE__" || true ? deleteFile : undefined} /* Simplified access control for UI purposes */
                formatSize={formatSize}
                formatDate={formatDate}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default FilesPage;
